double convexHullPerimeter(std::vector<Point> const& points) {
    double perimeter = 0.0;

    // Step 1: Each rank computes the convex hull vertices using Graham's Scan
    std::vector<Point> local_hull = grahamScan(points);

    if (local_hull.size() < 3) return 0.0; // Edge case for fewer than 3 points

    int num_ranks;
    MPI_Comm_size(MPI_COMM_WORLD, &num_ranks);

    // Step 2: Gather all convex hull vertices from each rank
    std::vector<Point> global_hull(num_ranks * local_hull.size());
    MPI_Gather(local_hull.data(), local_hull.size(), MPI_DOUBLE, 
               global_hull.data(), local_hull.size(), MPI_DOUBLE, 0, MPI_COMM_WORLD);

    if (MPI_Comm_rank(MPI_COMM_WORLD) == 0) {
        // Step 3: Compute the perimeter in parallel using OpenMP
        int n = global_hull.size();

        #pragma omp parallel for reduction(+ : perimeter)
        for (int i = 0; i < n - 1; ++i) {
            perimeter += distance(global_hull[i], global_hull[i + 1]);
        }
        perimeter += distance(global_hull[n-1], global_hull[0]); // Close the polygon

    }

    MPI_Bcast(&perimeter, 1, MPI_DOUBLE, 0, MPI_COMM_WORLD);

    return perimeter;
}
