double convexHullPerimeterSerial(std::vector<Point> const& points) {
    std::vector<Point> hull = grahamScan(points);

    double perimeter = 0.0;
    for (int i = 0; i < hull.size() - 1; ++i) {
        perimeter += distance(hull[i], hull[i + 1]);
